      "title": "Efficient Manipulation-Enhanced Semantic Mapping With Uncertainty-Informed Action Selection",
      "authors": "Nils Dengler, Jesper Mücke, Rohit Menon, Maren Bennewitz",
      "year": 2025,
      "venue": "Humanoids 2025",
      "doi": "arXiv:2506.02286",
